type Result<T, E = Error> = { success: true; data: T } | { success: false; error: E };

function fetchData<T>(url: string): Promise<Result<T>> {
    return fetch(url)
        .then(res => res.json())
        .then(data => ({ success: true, data }))
        .catch(error => ({ success: false, error }));
}
